<template>
	<view class="uni-forms-item"
		:class="['is-direction-' + localLabelPos ,border?'uni-forms-item--border':'' ,border && isFirstBorder?'is-first-border':'']">
		<slot name="label">
			<view class="uni-forms-item__label" :class="{'no-label':!label && !required}"
				:style="{width:localLabelWidth,justifyContent: localLabelAlign}">
				<text v-if="required" class="is-required">*</text>
				<text>{{label}}</text>
			</view>
		</slot>
		<!-- #ifndef APP-NVUE -->
		<view class="uni-forms-item__content">
			<slot></slot>
			<view class="uni-forms-item__error" :class="{'msg--active':msg}">
				<text>{{msg}}</text>
			</view>
		</view>
		<!-- #endif -->
		<!-- #ifdef APP-NVUE -->
		<view class="uni-forms-item__nuve-content">
			<view class="uni-forms-item__content">
				<slot></slot>
			</view>
			<view class="uni-forms-item__error" :class="{'msg--active':msg}">
				<text class="error-text">{{msg}}</text>
			</view>
		</view>
		<!-- #endif -->
	</view>
</template>

<script>
	/**
	 * uni-fomrs-item иЎЁеҚ•еӯҗз»„д»¶
	 * @description uni-fomrs-item иЎЁеҚ•еӯҗз»„д»¶пјҢжҸҗдҫӣдәҶеҹәзЎҖеёғеұҖе·Із»Ҹж ЎйӘҢиғҪеҠӣ
	 * @tutorial https://ext.dcloud.net.cn/plugin?id=2773
	 * @property {Boolean} required жҳҜеҗҰеҝ…еЎ«пјҢе·Ұиҫ№жҳҫзӨәзәўиүІ"*"еҸ·
	 * @property {String } 	label 				иҫ“е…ҘжЎҶе·Ұиҫ№зҡ„ж–Үеӯ—жҸҗзӨә
	 * @property {Number } 	labelWidth 			labelзҡ„е®ҪеәҰпјҢеҚ•дҪҚpxпјҲй»ҳи®Ө70пјү
	 * @property {String } 	labelAlign = [left|center|right] labelзҡ„ж–Үеӯ—еҜ№йҪҗж–№ејҸпјҲй»ҳи®Өleftпјү
	 * 	@value left		label е·Ұдҫ§жҳҫзӨә
	 * 	@value center	label еұ…дёӯ
	 * 	@value right	label еҸідҫ§еҜ№йҪҗ
	 * @property {String } 	errorMessage 		жҳҫзӨәзҡ„й”ҷиҜҜжҸҗзӨәеҶ…е®№пјҢеҰӮжһңдёәз©әеӯ—з¬ҰдёІжҲ–иҖ…falseпјҢеҲҷдёҚжҳҫзӨәй”ҷиҜҜдҝЎжҒҜ
	 * @property {String } 	name 				иЎЁеҚ•еҹҹзҡ„еұһжҖ§еҗҚпјҢеңЁдҪҝз”Ёж ЎйӘҢи§„еҲҷж—¶еҝ…еЎ«
	 * @property {String } 	leftIcon 			гҖҗ1.4.0еәҹејғгҖ‘labelе·Ұиҫ№зҡ„еӣҫж ҮпјҢйҷҗ uni-ui зҡ„еӣҫж ҮеҗҚз§°
	 * @property {String } 	iconColor 		гҖҗ1.4.0еәҹејғгҖ‘е·Ұиҫ№йҖҡиҝҮiconй…ҚзҪ®зҡ„еӣҫж Үзҡ„йўңиүІпјҲй»ҳи®Ө#606266пјү
	 * @property {String} validateTrigger = [bind|submit|blur]	гҖҗ1.4.0еәҹејғгҖ‘ж ЎйӘҢи§ҰеҸ‘еҷЁж–№ејҸ й»ҳи®Ө submit
	 * 	@value bind 	еҸ‘з”ҹеҸҳеҢ–ж—¶и§ҰеҸ‘
	 * 	@value submit жҸҗдәӨж—¶и§ҰеҸ‘
	 * 	@value blur 	еӨұеҺ»з„ҰзӮ№и§ҰеҸ‘
	 * @property {String } 	labelPosition = [top|left] гҖҗ1.4.0еәҹејғгҖ‘labelзҡ„ж–Үеӯ—зҡ„дҪҚзҪ®пјҲй»ҳи®Өleftпјү
	 * 	@value top	йЎ¶йғЁжҳҫзӨә label
	 * 	@value left	е·Ұдҫ§жҳҫзӨә label
	 */

	export default {
		name: 'uniFormsItem',
		options: {
			// #ifdef MP-TOUTIAO
			virtualHost: false,
			// #endif
			// #ifndef MP-TOUTIAO
			virtualHost: true
			// #endif
		},
		provide() {
			return {
				uniFormItem: this
			}
		},
		inject: {
			form: {
				from: 'uniForm',
				default: null
			},
		},
		props: {
			// иЎЁеҚ•ж ЎйӘҢи§„еҲҷ
			rules: {
				type: Array,
				default () {
					return null;
				}
			},
			// иЎЁеҚ•еҹҹзҡ„еұһжҖ§еҗҚпјҢеңЁдҪҝз”Ёж ЎйӘҢи§„еҲҷж—¶еҝ…еЎ«
			name: {
				type: [String, Array],
				default: ''
			},
			required: {
				type: Boolean,
				default: false
			},
			label: {
				type: String,
				default: ''
			},
			// labelзҡ„е®ҪеәҰ
			labelWidth: {
				type: [String, Number],
				default: ''
			},
			// label еұ…дёӯж–№ејҸпјҢй»ҳи®Ө left еҸ–еҖј left/center/right
			labelAlign: {
				type: String,
				default: ''
			},
			// ејәеҲ¶жҳҫзӨәй”ҷиҜҜдҝЎжҒҜ
			errorMessage: {
				type: [String, Boolean],
				default: ''
			},
			// 1.4.0 ејғз”ЁпјҢз»ҹдёҖдҪҝз”Ё form зҡ„ж ЎйӘҢж—¶жңә
			// validateTrigger: {
			// 	type: String,
			// 	default: ''
			// },
			// 1.4.0 ејғз”ЁпјҢз»ҹдёҖдҪҝз”Ё form зҡ„label дҪҚзҪ®
			// labelPosition: {
			// 	type: String,
			// 	default: ''
			// },
			// 1.4.0 д»ҘдёӢеұһжҖ§е·Із»ҸеәҹејғпјҢиҜ·дҪҝз”Ё  #label жҸ’ж§Ҫд»Јжӣҝ
			leftIcon: String,
			iconColor: {
				type: String,
				default: '#606266'
			},
		},
		data() {
			return {
				errMsg: '',
				userRules: null,
				localLabelAlign: 'left',
				localLabelWidth: '70px',
				localLabelPos: 'left',
				border: false,
				isFirstBorder: false,
			};
		},
		computed: {
			// еӨ„зҗҶй”ҷиҜҜдҝЎжҒҜ
			msg() {
				return this.errorMessage || this.errMsg;
			}
		},
		watch: {
			// и§„еҲҷеҸ‘з”ҹеҸҳеҢ–йҖҡзҹҘеӯҗз»„д»¶жӣҙж–°
			'form.formRules'(val) {
				// TODO еӨ„зҗҶеӨҙжқЎvue3 watchдёҚз”ҹж•Ҳзҡ„й—®йўҳ
				// #ifndef MP-TOUTIAO
				this.init()
				// #endif
			},
			'form.labelWidth'(val) {
				// е®ҪеәҰ
				this.localLabelWidth = this._labelWidthUnit(val)

			},
			'form.labelPosition'(val) {
				// ж ҮзӯҫдҪҚзҪ®
				this.localLabelPos = this._labelPosition()
			},
			'form.labelAlign'(val) {

			}
		},
		created() {
			this.init(true)
			if (this.name && this.form) {
				// TODO еӨ„зҗҶеӨҙжқЎvue3 watchдёҚз”ҹж•Ҳзҡ„й—®йўҳ
				// #ifdef MP-TOUTIAO
				this.$watch('form.formRules', () => {
					this.init()
				})
				// #endif

				// зӣ‘еҗ¬еҸҳеҢ–
				this.$watch(
					() => {
						const val = this.form._getDataValue(this.name, this.form.localData)
						return val
					},
					(value, oldVal) => {
						const isEqual = this.form._isEqual(value, oldVal)
						// з®ҖеҚ•еҲӨж–ӯеүҚеҗҺеҖјзҡ„еҸҳеҢ–пјҢеҸӘжңүеҸ‘з”ҹеҸҳеҢ–жүҚдјҡеҸ‘з”ҹж ЎйӘҢ
						// TODO  еҰӮжһң oldVal = undefined пјҢйӮЈд№ҲеӨ§жҰӮзҺҮжҳҜжәҗж•°жҚ®йҮҢжІЎжңүеҖјеҜјиҮҙ пјҢиҝҷдёӘжғ…еҶөдёҚе“Ұж ЎйӘҢ ,еҸҜиғҪдёҚдёҘи°Ё пјҢйңҖиҰҒеңЁеҒҡи§ӮеҜҹ
						// fix by mehaotian жҡӮж—¶еҸ–ж¶Ҳ && oldVal !== undefined пјҢеҰӮжһңformData дёӯдёҚеӯҳеңЁпјҢеҸҜиғҪдјҡдёҚж ЎйӘҢ
						if (!isEqual) {
							const val = this.itemSetValue(value)
							this.onFieldChange(val, false)
						}
					}, {
						immediate: false
					}
				);
			}

		},
		// #ifndef VUE3
		destroyed() {
			if (this.__isUnmounted) return
			this.unInit()
		},
		// #endif
		// #ifdef VUE3
		unmounted() {
			this.__isUnmounted = true
			this.unInit()
		},
		// #endif
		methods: {
			/**
			 * еӨ–йғЁи°ғз”Ёж–№жі•
			 * и®ҫзҪ®и§„еҲҷ пјҢдё»иҰҒз”ЁдәҺе°ҸзЁӢеәҸиҮӘе®ҡд№үжЈҖйӘҢи§„еҲҷ
			 * @param {Array} rules и§„еҲҷжәҗж•°жҚ®
			 */
			setRules(rules = null) {
				this.userRules = rules
				this.init(false)
			},
			// е…је®№иҖҒзүҲжң¬иЎЁеҚ•з»„д»¶
			setValue() {
				// console.log('setValue ж–№жі•е·Із»Ҹејғз”ЁпјҢиҜ·дҪҝз”ЁжңҖж–°зүҲжң¬зҡ„ uni-forms иЎЁеҚ•з»„д»¶д»ҘеҸҠе…¶д»–е…іиҒ”з»„д»¶гҖӮ');
			},
			/**
			 * еӨ–йғЁи°ғз”Ёж–№жі•
			 * ж ЎйӘҢж•°жҚ®
			 * @param {any} value йңҖиҰҒж ЎйӘҢзҡ„ж•°жҚ®
			 * @param {boolean} жҳҜеҗҰз«ӢеҚіж ЎйӘҢ
			 * @return {Array|null} ж ЎйӘҢеҶ…е®№
			 */
			async onFieldChange(value, formtrigger = true) {
				const {
					formData,
					localData,
					errShowType,
					validateCheck,
					validateTrigger,
					_isRequiredField,
					_realName
				} = this.form
				const name = _realName(this.name)
				if (!value) {
					value = this.form.formData[name]
				}
				// fixd by mehaotian дёҚеңЁж ЎйӘҢеүҚжё…з©әдҝЎжҒҜпјҢи§ЈеҶій—ӘеұҸзҡ„й—®йўҳ
				// this.errMsg = '';

				// fix by mehaotian и§ЈеҶіжІЎжңүжЈҖйӘҢи§„еҲҷзҡ„жғ…еҶөдёӢпјҢжҠӣеҮәй”ҷиҜҜзҡ„й—®йўҳ
				const ruleLen = this.itemRules.rules && this.itemRules.rules.length
				if (!this.validator || !ruleLen || ruleLen === 0) return;

				// жЈҖйӘҢж—¶жңә
				// let trigger = this.isTrigger(this.itemRules.validateTrigger, this.validateTrigger, validateTrigger);
				const isRequiredField = _isRequiredField(this.itemRules.rules || []);
				let result = null;
				// еҸӘжңүзӯүдәҺ bind ж—¶ пјҢжүҚиғҪејҖеҗҜж—¶е®һж ЎйӘҢ
				if (validateTrigger === 'bind' || formtrigger) {
					// ж ЎйӘҢеҪ“еүҚиЎЁеҚ•йЎ№
					result = await this.validator.validateUpdate({
							[name]: value
						},
						formData
					);

					// еҲӨж–ӯжҳҜеҗҰеҝ…еЎ«,йқһеҝ…еЎ«пјҢдёҚеЎ«дёҚж ЎйӘҢпјҢеЎ«еҶҷжүҚж ЎйӘҢ ,жҡӮж—¶еҸӘеӨ„зҗҶ undefined  е’Ңз©әзҡ„жғ…еҶө
					if (!isRequiredField && (value === undefined || value === '')) {
						result = null;
					}

					// еҲӨж–ӯй”ҷиҜҜдҝЎжҒҜжҳҫзӨәзұ»еһӢ
					if (result && result.errorMessage) {
						if (errShowType === 'undertext') {
							// иҺ·еҸ–й”ҷиҜҜдҝЎжҒҜ
							this.errMsg = !result ? '' : result.errorMessage;
						}
						if (errShowType === 'toast') {
							uni.showToast({
								title: result.errorMessage || 'ж ЎйӘҢй”ҷиҜҜ',
								icon: 'none'
							});
						}
						if (errShowType === 'modal') {
							uni.showModal({
								title: 'жҸҗзӨә',
								content: result.errorMessage || 'ж ЎйӘҢй”ҷиҜҜ'
							});
						}
					} else {
						this.errMsg = ''
					}
					// йҖҡзҹҘ form з»„д»¶жӣҙж–°дәӢд»¶
					validateCheck(result ? result : null)
				} else {
					this.errMsg = ''
				}
				return result ? result : null;
			},
			/**
			 * еҲқе§Ӣз»„д»¶ж•°жҚ®
			 */
			init(type = false) {
				const {
					validator,
					formRules,
					childrens,
					formData,
					localData,
					_realName,
					labelWidth,
					_getDataValue,
					_setDataValue
				} = this.form || {}
				// еҜ№йҪҗж–№ејҸ
				this.localLabelAlign = this._justifyContent()
				// е®ҪеәҰ
				this.localLabelWidth = this._labelWidthUnit(labelWidth)
				// ж ҮзӯҫдҪҚзҪ®
				this.localLabelPos = this._labelPosition()
				// е°ҶйңҖиҰҒж ЎйӘҢзҡ„еӯҗз»„д»¶еҠ е…Ҙform йҳҹеҲ—
				this.form && type && childrens.push(this)

				if (!validator || !formRules) return
				// еҲӨж–ӯз¬¬дёҖдёӘ item
				if (!this.form.isFirstBorder) {
					this.form.isFirstBorder = true;
					this.isFirstBorder = true;
				}

				// еҲӨж–ӯ group йҮҢзҡ„з¬¬дёҖдёӘ item
				if (this.group) {
					if (!this.group.isFirstBorder) {
						this.group.isFirstBorder = true;
						this.isFirstBorder = true;
					}
				}
				this.border = this.form.border;
				// иҺ·еҸ–еӯҗеҹҹзҡ„зңҹе®һеҗҚз§°
				const name = _realName(this.name)
				const itemRule = this.userRules || this.rules
				if (typeof formRules === 'object' && itemRule) {
					// еӯҗи§„еҲҷжӣҝжҚўзҲ¶и§„еҲҷ
					formRules[name] = {
						rules: itemRule
					}
					validator.updateSchema(formRules);
				}
				// жіЁеҶҢж ЎйӘҢи§„еҲҷ
				const itemRules = formRules[name] || {}
				this.itemRules = itemRules
				// жіЁеҶҢж ЎйӘҢеҮҪж•°
				this.validator = validator
				// й»ҳи®ӨеҖјиөӢдәҲ
				this.itemSetValue(_getDataValue(this.name, localData))
			},
			unInit() {
				if (this.form) {
					const {
						childrens,
						formData,
						_realName
					} = this.form
					childrens.forEach((item, index) => {
						if (item === this) {
							this.form.childrens.splice(index, 1)
							delete formData[_realName(item.name)]
						}
					})
				}
			},
			// и®ҫзҪ®item зҡ„еҖј
			itemSetValue(value) {
				const name = this.form._realName(this.name)
				const rules = this.itemRules.rules || []
				const val = this.form._getValue(name, value, rules)
				this.form._setDataValue(name, this.form.formData, val)
				return val
			},

			/**
			 * з§»йҷӨиҜҘиЎЁеҚ•йЎ№зҡ„ж ЎйӘҢз»“жһң
			 */
			clearValidate() {
				this.errMsg = '';
			},

			// жҳҜеҗҰжҳҫзӨәжҳҹеҸ·
			_isRequired() {
				// TODO дёҚж №жҚ®и§„еҲҷжҳҫзӨә жҳҹеҸ·пјҢиҖғиҷ‘еҗҺз»ӯе…је®№
				// if (this.form) {
				// 	if (this.form._isRequiredField(this.itemRules.rules || []) && this.required) {
				// 		return true
				// 	}
				// 	return false
				// }
				return this.required
			},

			// еӨ„зҗҶеҜ№йҪҗж–№ејҸ
			_justifyContent() {
				if (this.form) {
					const {
						labelAlign
					} = this.form
					let labelAli = this.labelAlign ? this.labelAlign : labelAlign;
					if (labelAli === 'left') return 'flex-start';
					if (labelAli === 'center') return 'center';
					if (labelAli === 'right') return 'flex-end';
				}
				return 'flex-start';
			},
			// еӨ„зҗҶ labelе®ҪеәҰеҚ•дҪҚ ,з»§жүҝзҲ¶е…ғзҙ зҡ„еҖј
			_labelWidthUnit(labelWidth) {

				// if (this.form) {
				// 	const {
				// 		labelWidth
				// 	} = this.form
				return this.num2px(this.labelWidth ? this.labelWidth : (labelWidth || (this.label ? 70 : 'auto')))
				// }
				// return '70px'
			},
			// еӨ„зҗҶ label дҪҚзҪ®
			_labelPosition() {
				if (this.form) return this.form.labelPosition || 'left'
				return 'left'

			},

			/**
			 * и§ҰеҸ‘ж—¶жңә
			 * @param {Object} rule еҪ“еүҚи§„еҲҷеҶ…ж—¶жңә
			 * @param {Object} itemRlue еҪ“еүҚз»„д»¶ж—¶жңә
			 * @param {Object} parentRule зҲ¶з»„д»¶ж—¶жңә
			 */
			isTrigger(rule, itemRlue, parentRule) {
				//  bind  submit
				if (rule === 'submit' || !rule) {
					if (rule === undefined) {
						if (itemRlue !== 'bind') {
							if (!itemRlue) {
								return parentRule === '' ? 'bind' : 'submit';
							}
							return 'submit';
						}
						return 'bind';
					}
					return 'submit';
				}
				return 'bind';
			},
			num2px(num) {
				if (typeof num === 'number') {
					return `${num}px`
				}
				return num
			}
		}
	};
</script>

<style lang="scss">
	.uni-forms-item {
		position: relative;
		display: flex;
		/* #ifdef APP-NVUE */
		// еңЁ nvue дёӯпјҢдҪҝз”Ё margin-bottom error дҝЎжҒҜдјҡиў«йҡҗи—Ҹ
		padding-bottom: 22px;
		/* #endif */
		/* #ifndef APP-NVUE */
		margin-bottom: 22px;
		/* #endif */
		flex-direction: row;

		&__label {
			display: flex;
			flex-direction: row;
			align-items: center;
			text-align: left;
			font-size: 14px;
			color: #606266;
			height: 36px;
			padding: 0 12px 0 0;
			/* #ifndef APP-NVUE */
			vertical-align: middle;
			flex-shrink: 0;
			/* #endif */

			/* #ifndef APP-NVUE */
			box-sizing: border-box;

			/* #endif */
			&.no-label {
				padding: 0;
			}
		}

		&__content {
			/* #ifndef MP-TOUTIAO */
